    background: #eff6ff;
    border-radius: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
}
[data-theme="dark"] .hub-card-icon-wrap { background: rgba(37,99,168,.18); }
.hub-card-icon-wrap svg {
    width: 24px;
    height: 24px;
    stroke: var(--primary-light);
    flex-shrink: 0;
}
.hub-card-title {
