    <div class="hub-grid">
        @foreach($cards as $card)
        @php
            $isActive = isset($card['route']) && $rota === $card['route'];
            $disabled = !empty($card['disabled']);
            $url      = (!$disabled && isset($card['route'])) ? route($card['route']) : '#';
            $classes  = 'hub-card' . ($isActive ? ' hub-card-active' : '') . ($disabled ? ' hub-card-disabled' : '');
            $iconKey  = $card['icon'] ?? '';
            $svg      = $svgs[$iconKey] ?? $svgs['documentos'];
        @endphp
        <a href="{{ $url }}" class="{{ $classes }}">
            <div class="hub-card-accent"></div>
            <div class="hub-card-body">
                <div class="hub-card-icon-wrap">{!! $svg !!}</div>
                <div class="hub-card-title">{{ $card['title'] }}</div>
                <div class="hub-card-desc">{{ $card['desc'] ?? '' }}</div>
                @if($isActive)<div class="hub-card-badge">✓ Página atual</div>@endif
            </div>
        </a>
        @endforeach
    </div>
